#!/bin/bash
# gateway v3 — принудительный поиск для курсов/погоды (точные данные)
mkdir -p ~/gateway/data
cat > /tmp/gw3_b64.txt << 'GWEOF'

GWEOF
base64 -d /tmp/gw3_b64.txt > ~/gateway/gateway.py
echo "Строк:"; wc -l ~/gateway/gateway.py
python3 -c "import ast; ast.parse(open('/home/ubuntu/gateway/gateway.py').read()); print('OK - синтаксис валиден')"
